easy.starterCode:
.card { border-radius: 8px; background: white; }
.card__title { color: #0055CC; font-size: 1.25rem; }
.card__text { color: #666; font-size: 1rem; }
.card--featured { border: 2px solid #0055CC; }
.btn { padding: 0.5rem 1rem; border-radius: 6px; }
.btn--primary { background: #0055CC; color: white; }
.btn--secondary { background: transparent; border: 1px solid #0055CC; color: #0055CC; }

easy.solution:
$primary: #0055CC;
$radius: 8px;
$text-dark: #333;
$text-muted: #666;

.card {
  border-radius: $radius;
  background: white;

  &__title {
    color: $primary;
    font-size: 1.25rem;
  }

  &__text {
    color: $text-muted;
    font-size: 1rem;
  }

  &--featured {
    border: 2px solid $primary;
  }
}

.btn {
  padding: 0.5rem 1rem;
  border-radius: 6px;

  &--primary {
    background: $primary;
    color: white;
  }

  &--secondary {
    background: transparent;
    border: 1px solid $primary;
    color: $primary;
  }
}

medium.starterCode:
.grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}

@media (min-width: 768px) {
  .grid { grid-template-columns: 1fr 1fr; }
}

@media (min-width: 1024px) {
  .grid { grid-template-columns: 1fr 1fr 1fr; }
}

.header { font-size: 1.5rem; }
@media (min-width: 768px) {
  .header { font-size: 2rem; }
}

medium.solution:
@mixin respond-to($bp) {
  @media (min-width: $bp) {
    @content;
  }
}

.grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;

  @include respond-to(768px) {
    grid-template-columns: 1fr 1fr;
  }

  @include respond-to(1024px) {
    grid-template-columns: 1fr 1fr 1fr;
  }
}

.header {
  font-size: 1.5rem;

  @include respond-to(768px) {
    font-size: 2rem;
  }

  @include respond-to(1024px) {
    font-size: 2.5rem;
  }
}

hard.starterCode:
.text-primary { color: #0055CC; }
.text-success { color: #16A34A; }
.text-danger { color: #DC2626; }
.text-warning { color: #F59E0B; }

.bg-primary { background: #0055CC; }
.bg-success { background: #16A34A; }
.bg-danger { background: #DC2626; }
.bg-warning { background: #F59E0B; }

/* Now imagine repeating for md: and lg: prefixes... too much duplication! */

hard.solution:
@mixin respond-to($bp) {
  @media (min-width: $bp) {
    @content;
  }
}

$colors: (
  'primary': #0055CC,
  'success': #16A34A,
  'danger': #DC2626,
  'warning': #F59E0B,
);

@each $name, $color in $colors {
  .text-#{$name} {
    color: $color;
  }
  .bg-#{$name} {
    background: $color;
  }
}

$breakpoints: (
  'md': 768px,
  'lg': 1024px,
);

@each $bp-name, $bp-value in $breakpoints {
  @include respond-to($bp-value) {
    @each $name, $color in $colors {
      .#{$bp-name}\:text-#{$name} {
        color: $color;
      }
      .#{$bp-name}\:bg-#{$name} {
        background: $color;
      }
    }
  }
}
